CREATE TABLE IF NOT EXISTS `audit_logs` (`id` INTEGER NOT NULL AUTO_INCREMENT, `userId` INTEGER NULL, `action` VARCHAR(100) NOT NULL, `target` VARCHAR(255) NULL, `detail` JSON NULL, `ip` VARCHAR(45) NULL, `ua` VARCHAR(500) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), INDEX `audit_logs_userId_createdAt_idx`(`userId`, `createdAt`), INDEX `audit_logs_action_createdAt_idx`(`action`, `createdAt`), INDEX `audit_logs_createdAt_idx`(`createdAt`), PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;